SELECT facility_name
FROM facilities
ORDER BY facility_name;

SELECT facility_id, SUM(total_reprieves) AS total_reprieves_given
FROM reprieve_statistics
WHERE facility_id = 0;

SELECT date, population, admissions
FROM population_records
WHERE facility_id = 1 AND date = '2020-10-29';

SELECT yearly_reprieves
FROM reprieve_statistics
WHERE facility_id = 0;

SELECT SUM(total_reprieves) AS total_reprieves_given
FROM reprieve_statistics
WHERE facility_id = 1;

SELECT population
FROM population_records
WHERE facility_id = 1 AND date = '2020-10-29';

SELECT population AS total_population
FROM population_records
WHERE facility_id = 0 AND date = '2020-10-29';

SELECT MIN(population) AS min_population
FROM population_records
WHERE facility_id = 1;
